{
  "summary": "This paper presents a systematic quantification of exposure bias impact in open-ended language generation by proposing two novel metrics (EB-M and EB-C) that measure quality, diversity, and consistency differences when conditioning on model versus data prefixes. Through extensive experiments, including synthetic settings and human evaluation, the authors find that exposure bias causes only minor degradation and that MLE-trained models exhibit a self-recovery ability, challenging the common belief that exposure bias is a major issue.",
  "strengths": [
    {
      "point": "Novel systematic quantification of exposure bias impact",
      "evidence": "The paper introduces two novel metrics, EB-M and EB-C, to measure exposure bias effects on quality, diversity, and consistency, providing a structured approach to a previously under-quantified problem."
    },
    {
      "point": "Comprehensive experimental evaluation including synthetic and human studies",
      "evidence": "Experiments span multiple datasets, model types, and include a synthetic setting where ground-truth distributions are known, as well as human evaluations confirming quantitative findings."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior exposure bias quantification methods",
      "evidence": "The paper lacks a thorough literature review and empirical comparison to prior works like scheduled sampling or professor forcing that also attempt to measure exposure bias."
    },
    {
      "point": "Limited justification and clarity of proposed metrics and methodology",
      "evidence": "The rationale for choosing EB-M and EB-C metrics is not fully explained, especially reliance on corpus-BLEU and divergence measures without addressing their limitations; also, the 'comfortable zone' concept and EB-C estimation details are ambiguous."
    }
  ],
  "questions": [
    {
      "question": "How do exposure bias effects vary across different model architectures, training regimes, and generation tasks beyond open-ended language generation?",
      "motivation": "Understanding generalizability is crucial since the paper focuses on a limited set of MLE-trained transformers and open-ended generation, while exposure bias might manifest differently in tasks like translation or dialogue."
    },
    {
      "question": "What is the impact of model size, training data scale, and prefix sampling strategies on the severity of exposure bias?",
      "motivation": "Exploring these factors could clarify whether exposure bias effects change with larger models or different sampling methods, which is important for practical deployment and metric robustness."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
